data.content:
Use MSTest's `[DataTestMethod]` with `[DataRow]` to make these data-driven. You can group by expected outcome:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("", "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow(null, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("   ", "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", "Input contains invalid characters", DisplayName = "Special chars")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    [DataTestMethod]
    [DataRow("hello-world", DisplayName = "Typical input")]
    [DataRow("abc", DisplayName = "Min length (3)")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    [TestMethod]
    public void Validate_TooLong_ReturnsFalse()
    {
        // DataRow requires compile-time constants, so computed values stay in their own method
        var result = _validator.Validate(new string('x', 256));
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual("Input must not exceed 255 characters", result.ErrorMessage);
    }

    [TestMethod]
    public void Validate_MaxLength_ReturnsTrue()
    {
        var result = _validator.Validate(new string('a', 255));
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }
}
```

**Key changes:**

- **`[DataTestMethod]` + `[DataRow]`** — each row is a separate test run; adding a case is one line, not a whole method.
- **`[TestInitialize]`** — eliminates repeated `new InputValidator()`.
- **`DisplayName`** — gives readable names in Test Explorer.
- Cases using `new string(...)` stay as regular `[TestMethod]`s since `DataRow` requires compile-time constants.

If you later need runtime-computed values as data too, look into `[DynamicData]` which can pull from a static method/property.
